# Category: saml_signature_wrapping

from flask import Flask, request, redirect, session, url_for
import xml.etree.ElementTree as ET
import base64

app = Flask(__name__)
app.secret_key = 'your_secret_key'

@app.route('/saml/consume', methods=['POST'])
def consume_saml_response():
    saml_response = request.form.get('SAMLResponse')
    if not saml_response:
        return "No SAML Response", 400

    decoded_response = base64.b64decode(saml_response)
    root = ET.fromstring(decoded_response)

    # Namespace handling
    ns = {'saml': 'urn:oasis:names:tc:SAML:2.0:assertion'}

    # Validate Assertion presence
    assertions = root.findall('.//saml:Assertion', ns)
    if not assertions:
        return "No Assertions found", 400

    # Extract user attributes
    user_attributes = {}
    for assertion in assertions:
        for attribute in assertion.findall('.//saml:Attribute', ns):
            attr_name = attribute.get('Name')
            attr_value = attribute.find('.//saml:AttributeValue', ns).text
            user_attributes[attr_name] = attr_value

    # Create user session
    session['user'] = user_attributes

    return redirect(url_for('welcome'))

@app.route('/welcome')
def welcome():
    if 'user' not in session:
        return redirect(url_for('index'))
    return f"Welcome {session['user'].get('name', 'User')}!"

@app.route('/')
def index():
    return "Home Page - Please authenticate via SSO."

if __name__ == '__main__':
    app.run(debug=True)